// StrictServerInterface represents all server handlers.
type StrictServerInterface interface {
	// List access log entries
	// (GET /access-log)
	GetAccessLog(ctx context.Context, request GetAccessLogRequestObject) (GetAccessLogResponseObject, error)
	// List valid deny reason values
	// (GET /access-log/deny-reasons)
	GetAccessLogDenyReasons(ctx context.Context, request GetAccessLogDenyReasonsRequestObject) (GetAccessLogDenyReasonsResponseObject, error)
	// Request counts grouped by country
	// (GET /access-log/stats/by-country)
	GetAccessLogByCountry(ctx context.Context, request GetAccessLogByCountryRequestObject) (GetAccessLogByCountryResponseObject, error)
	// Get address activity history
	// (GET /address-history)
	GetAddressHistory(ctx context.Context, request GetAddressHistoryRequestObject) (GetAddressHistoryResponseObject, error)
	// List all users (Admin only)
	// (GET /admin/users)
	ListUsers(ctx context.Context, request ListUsersRequestObject) (ListUsersResponseObject, error)
	// Register a new user (Admin only)
	// (POST /admin/users)
	CreateUser(ctx context.Context, request CreateUserRequestObject) (CreateUserResponseObject, error)
	// Delete a user (Admin only)
	// (DELETE /admin/users/{user_id})
	DeleteUser(ctx context.Context, request DeleteUserRequestObject) (DeleteUserResponseObject, error)
	// Demote an admin to regular user (Admin only)
	// (POST /admin/users/{user_id}/demote)
	DemoteUser(ctx context.Context, request DemoteUserRequestObject) (DemoteUserResponseObject, error)
	// List devices owned by a user (Admin only)
	// (GET /admin/users/{user_id}/devices)
	GetDevicesByUser(ctx context.Context, request GetDevicesByUserRequestObject) (GetDevicesByUserResponseObject, error)
	// Promote a user to admin (Admin only)
	// (POST /admin/users/{user_id}/promote)
	PromoteUser(ctx context.Context, request PromoteUserRequestObject) (PromoteUserResponseObject, error)
	// Login user
	// (POST /auth/login)
	Login(ctx context.Context, request LoginRequestObject) (LoginResponseObject, error)
	// Logout user
	// (POST /auth/logout)
	Logout(ctx context.Context, request LogoutRequestObject) (LogoutResponseObject, error)
	// Get current user
	// (GET /auth/me)
	GetCurrentUser(ctx context.Context, request GetCurrentUserRequestObject) (GetCurrentUserResponseObject, error)
	// Dashboard service breakdown
	// (GET /dashboard/services)
	GetDashboardServices(ctx context.Context, request GetDashboardServicesRequestObject) (GetDashboardServicesResponseObject, error)
	// Dashboard summary statistics
	// (GET /dashboard/stats)
	GetDashboardStats(ctx context.Context, request GetDashboardStatsRequestObject) (GetDashboardStatsResponseObject, error)
	// Dashboard top denied IPs
	// (GET /dashboard/top-denied-ips)
	GetDashboardTopDeniedIps(ctx context.Context, request GetDashboardTopDeniedIpsRequestObject) (GetDashboardTopDeniedIpsResponseObject, error)
	// Dashboard traffic time series
	// (GET /dashboard/traffic)
	GetDashboardTraffic(ctx context.Context, request GetDashboardTrafficRequestObject) (GetDashboardTrafficResponseObject, error)
	// List device types
	// (GET /device-types)
	ListDeviceTypes(ctx context.Context, request ListDeviceTypesRequestObject) (ListDeviceTypesResponseObject, error)
	// List all devices
	// (GET /devices)
	GetDevices(ctx context.Context, request GetDevicesRequestObject) (GetDevicesResponseObject, error)
	// Create a device
	// (POST /devices)
	CreateDevice(ctx context.Context, request CreateDeviceRequestObject) (CreateDeviceResponseObject, error)
	// Delete a device
	// (DELETE /devices/{device_id})
	DeleteDevice(ctx context.Context, request DeleteDeviceRequestObject) (DeleteDeviceResponseObject, error)
	// Get a device
	// (GET /devices/{device_id})
	GetDevice(ctx context.Context, request GetDeviceRequestObject) (GetDeviceResponseObject, error)
	// Update device profile
	// (PATCH /devices/{device_id})
	UpdateDevice(ctx context.Context, request UpdateDeviceRequestObject) (UpdateDeviceResponseObject, error)
	// Get addresses for a device
	// (GET /devices/{device_id}/addresses)
	GetDeviceAddresses(ctx context.Context, request GetDeviceAddressesRequestObject) (GetDeviceAddressesResponseObject, error)
	// Assign address to device
	// (POST /devices/{device_id}/addresses)
	AddAddress(ctx context.Context, request AddAddressRequestObject) (AddAddressResponseObject, error)
	// Disable address
	// (DELETE /devices/{device_id}/addresses/{address_id})
	DisableAddress(ctx context.Context, request DisableAddressRequestObject) (DisableAddressResponseObject, error)
	// Regenerate device API key
	// (POST /devices/{device_id}/api-key/regenerate)
	RegenerateDeviceAPIKey(ctx context.Context, request RegenerateDeviceAPIKeyRequestObject) (RegenerateDeviceAPIKeyResponseObject, error)
	// Device heartbeat
	// (POST /devices/{device_id}/heartbeat)
	DeviceHeartbeat(ctx context.Context, request DeviceHeartbeatRequestObject) (DeviceHeartbeatResponseObject, error)
	// Disable device lease rule for a device
	// (DELETE /devices/{device_id}/rules/address_lease)
	DisableDeviceAddressLeaseRule(ctx context.Context, request DisableDeviceAddressLeaseRuleRequestObject) (DisableDeviceAddressLeaseRuleResponseObject, error)
	// Get address lease rule for a device
	// (GET /devices/{device_id}/rules/address_lease)
	GetDeviceAddressLeaseRule(ctx context.Context, request GetDeviceAddressLeaseRuleRequestObject) (GetDeviceAddressLeaseRuleResponseObject, error)
	// Create or update IP auto-expiry rule for a device
	// (PUT /devices/{device_id}/rules/address_lease)
	PutDeviceAddressLeaseRule(ctx context.Context, request PutDeviceAddressLeaseRuleRequestObject) (PutDeviceAddressLeaseRuleResponseObject, error)
	// Disable max active addresses rule for a device
	// (DELETE /devices/{device_id}/rules/max_active_addresses)
	DisableMaxActiveAddressesRule(ctx context.Context, request DisableMaxActiveAddressesRuleRequestObject) (DisableMaxActiveAddressesRuleResponseObject, error)
	// Get max active addresses rule for a device
	// (GET /devices/{device_id}/rules/max_active_addresses)
	GetMaxActiveAddressesRule(ctx context.Context, request GetMaxActiveAddressesRuleRequestObject) (GetMaxActiveAddressesRuleResponseObject, error)
	// Create or update max active addresses rule for a device
	// (PUT /devices/{device_id}/rules/max_active_addresses)
	PutMaxActiveAddressesRule(ctx context.Context, request PutMaxActiveAddressesRuleRequestObject) (PutMaxActiveAddressesRuleResponseObject, error)
	// Performs a heartbeat with the given api key header
	// (POST /heartbeat)
	DeviceHeartbeatByAPIKey(ctx context.Context, request DeviceHeartbeatByAPIKeyRequestObject) (DeviceHeartbeatByAPIKeyResponseObject, error)
	// Update current user profile
	// (PATCH /users/me)
	UpdateMe(ctx context.Context, request UpdateMeRequestObject) (UpdateMeResponseObject, error)
	// Change current user password
	// (POST /users/me/password)
	ChangePassword(ctx context.Context, request ChangePasswordRequestObject) (ChangePasswordResponseObject, error)
}

type StrictHandlerFunc = strictnethttp.StrictHTTPHandlerFunc
type StrictMiddlewareFunc = strictnethttp.StrictHTTPMiddlewareFunc

type StrictHTTPServerOptions struct {
	RequestErrorHandlerFunc  func(w http.ResponseWriter, r *http.Request, err error)
	ResponseErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

func NewStrictHandler(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: StrictHTTPServerOptions{
		RequestErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		},
		ResponseErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusInternalServerError)
		},
	}}
}

func NewStrictHandlerWithOptions(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc, options StrictHTTPServerOptions) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: options}
}

